class Solution(object):
 def solve(self, nums):
 n = len(nums)
 for i in range(n):
 for j in range(n - i - 1):
 if nums[j] > nums[j + 1]:
 nums[j], nums[j + 1] = nums[j + 1], nums[j]
 return nums

 def main():
 import sys

 nums = list(map(int, sys.stdin.readline().split()))

 solution = Solution()

 result = solution.solve(nums)

 print(" " . join(map(str, result)))

 if __name__ == '__main__':
 main()

