#include <iostream>
#include <vector>
#include <algorithm>

 using namespace std;

 class Solution {
 public:
 bool solve(vector<int>& nums) {
 n = nums.size();
 for (int i = 0; i < n; i++) {
 for (int j = 0; j < n - i - 1; j++) {
 if (nums[j] > nums[j + 1]) {
 swap(nums[j], nums[j + 1]);
 }
 }
 }
 return true;
 }
 private:
 int n;
 };

 int main() {
 vector<int> nums;
 int num;
 while (cin >> num) {
 nums.push_back(num);
 }
 Solution solution;
 solution.solve(nums);
 for (int i = 0; i < nums.size(); i++) {
 cout << nums[i] << ' ';
 }
 cout << endl;
 return 0;
}
